export default function AtsellLanding() {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 50);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <div style={{ fontFamily: "'DM Sans', sans-serif", WebkitFontSmoothing: "antialiased" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:ital,wght@0,400;0,500;0,600;0,700;0,800;1,400&family=Playfair+Display:wght@400;600;700;0,800&display=swap');

        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
        html { scroll-behavior: smooth; }
        body { overflow-x: hidden; }

        @keyframes pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.5; transform: scale(0.8); }
        }

        @keyframes scrollLogos {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }

        .case-study-scroll::-webkit-scrollbar { display: none; }
        .case-study-scroll { -ms-overflow-style: none; scrollbar-width: none; }

        @media (max-width: 768px) {
          .case-stats-grid { grid-template-columns: 1fr 1fr !important; }
          .hero-grid { grid-template-columns: 1fr !important; }
          .hero-stats-col { display: none !important; }
          .desktop-nav { display: none !important; }
          .mobile-burger { display: flex !important; }
          .case-study-grid { grid-template-columns: 1fr !important; }
          .deliverables-grid { grid-template-columns: 1fr !important; }
        }
        @media (min-width: 769px) {
          .mobile-burger { display: none !important; }
        }
      `}</style>

      <NavBar scrolled={scrolled} />
      <Hero />
      <TrustBar />
      <Services />
      <WhyUs />
      <Results />
      <Testimonials />
      <Pricing />
      <Calculator />
      <Footer />
    </div>
  );
}
